record_types.code:
type Control_System_State is record
   Time_Usec    : Interfaces.Unsigned_64;
   X_Acc        : Raw_Float;
   Y_Acc        : Raw_Float;
   Z_Acc        : Raw_Float;
   X_Vel        : Raw_Float;
   Y_Vel        : Raw_Float;
   Z_Vel        : Raw_Float;
   X_Pos        : Raw_Float;
   Y_Pos        : Raw_Float;
   Z_Pos        : Raw_Float;
   Airspeed     : Raw_Float :=
     To_Raw (-1.0);
   Vel_Variance : Short_Float_Array (1 .. 3);
   Pos_Variance : Short_Float_Array (1 .. 3);
   Q            : Short_Float_Array (1 .. 4);
   Roll_Rate    : Raw_Float;
   Pitch_Rate   : Raw_Float;
   Yaw_Rate     : Raw_Float;
end record;

